import{_ as t,H as a,f as o,i as e}from"./chunks/framework.Cvt1eIE0.js";const u=JSON.parse('{"title":"项目经历","description":"","frontmatter":{},"headers":[],"relativePath":"projects.md","filePath":"projects.md","lastUpdated":1778828851000}'),n={name:"projects.md"};function i(l,r,s,h,g,d){return a(),o("div",null,[...r[0]||(r[0]=[e('<h1 id="项目经历" tabindex="-1">项目经历 <a class="header-anchor" href="#项目经历" aria-label="Permalink to &quot;项目经历&quot;">​</a></h1><h2 id="全国产化新型电力系统仿真软件-simunps" tabindex="-1">全国产化新型电力系统仿真软件 SimuNPS <a class="header-anchor" href="#全国产化新型电力系统仿真软件-simunps" aria-label="Permalink to &quot;全国产化新型电力系统仿真软件 SimuNPS&quot;">​</a></h2><p><strong>时间</strong>：2021年至今<br><strong>职责</strong>：电力电子设备建模、高效并行化算法开发、软件操作逻辑设计、智能潮流计算开发<br><strong>官网</strong>：<a href="https://www.simunps.com/" target="_blank" rel="noreferrer">https://www.simunps.com/</a></p><h3 id="项目背景" tabindex="-1">项目背景 <a class="header-anchor" href="#项目背景" aria-label="Permalink to &quot;项目背景&quot;">​</a></h3><p>常用电力系统仿真软件如 PSCAD、PowerFactory 等长期被欧美国家垄断，存在较大的断供风险。电力系统事关国家能源安全，对核心仿真软件的国产化替代具有迫切需求。</p><h3 id="我的工作" tabindex="-1">我的工作 <a class="header-anchor" href="#我的工作" aria-label="Permalink to &quot;我的工作&quot;">​</a></h3><p>基于本人在电力系统仿真领域的技术积累，深度参与了全国产化新型电力系统仿真软件 SimuNPS 的研发工作。作为<strong>建模与算法技术负责人</strong>，主要负责：</p><ul><li>电力电子装备模型与变压器模型设计</li><li>高效并行算法开发</li><li>软件操作逻辑设计</li><li>智能化潮流计算等关键模块</li></ul><h3 id="成果" tabindex="-1">成果 <a class="header-anchor" href="#成果" aria-label="Permalink to &quot;成果&quot;">​</a></h3><p>相关成果已在<strong>数十所高校和科研院所</strong>推广应用，服务于电力系统仿真、新能源并网稳定分析及电路原理教学实验等多类场景。</p><p>目前，SimuNPS 已完成全面升级并正式发布 <strong>V3 版本</strong>，支持国产麒麟操作系统，并面向全球开放试用申请。</p><hr><h2 id="大规模风电场精细化实时仿真平台-digwind" tabindex="-1">大规模风电场精细化实时仿真平台 DigWind <a class="header-anchor" href="#大规模风电场精细化实时仿真平台-digwind" aria-label="Permalink to &quot;大规模风电场精细化实时仿真平台 DigWind&quot;">​</a></h2><p><strong>时间</strong>：2020年至今<br><strong>职责</strong>：风电精细化建模方法设计、并行算法设计<br><strong>官网</strong>：<a href="http://www.zhaohaoran.top/platform.html" target="_blank" rel="noreferrer">http://www.zhaohaoran.top/platform.html</a></p><h3 id="项目背景-1" tabindex="-1">项目背景 <a class="header-anchor" href="#项目背景-1" aria-label="Permalink to &quot;项目背景&quot;">​</a></h3><p>风电出力具有显著不确定性，大规模并网运行容易诱发宽频振荡等稳定性问题，极端情况下可能引发区域性大停电事故，严重威胁电力系统的安全稳定运行。现有风电仿真多采用简化模型，忽略了大量关键动态过程，仿真结果难以真实反映实际运行特性。</p><h3 id="我的工作-1" tabindex="-1">我的工作 <a class="header-anchor" href="#我的工作-1" aria-label="Permalink to &quot;我的工作&quot;">​</a></h3><p>在导师的指导下，开展了大规模风电场精细化实时仿真平台的研发工作：</p><ul><li>提出面向多物理场耦合的风电场<strong>精细化建模方法</strong></li><li>构建基于 <strong>GPU/FPGA</strong> 的高效并行计算算法</li><li>研制 <strong>DigWind 软硬件一体化仿真平台</strong></li><li>实现仿真&quot;<strong>又准又快</strong>&quot;，有效支撑百台机组规模风电场在多种工况下的快速验证</li></ul><h3 id="成果与荣誉" tabindex="-1">成果与荣誉 <a class="header-anchor" href="#成果与荣誉" aria-label="Permalink to &quot;成果与荣誉&quot;">​</a></h3><ul><li>被电力系统仿真领域奠基人<strong>周孝信院士</strong>评价为达到<strong>国际领先水平</strong></li><li>荣获 <strong>2022 年度日内瓦国际发明展银奖</strong></li><li>荣获 <strong>2025 年度中国仿真学会创新技术一等奖</strong></li><li>带队参加第十八届中国研究生电子设计竞赛，获得： <ul><li><strong>全国总决赛团队一等奖</strong></li><li><strong>最佳路演奖</strong></li><li><strong>最具投资价值奖</strong>（全国唯一同时获此三项）</li></ul></li></ul>',21)])])}const c=t(n,[["render",i]]);export{u as __pageData,c as default};
